import { jsx, jsxs, Fragment } from 'react/jsx-runtime';
import { forwardRef } from 'react';
import { Tooltip } from '../Tooltip/Tooltip.js';
import { CounterBody } from './CounterBody/CounterBody.js';

const Counter = forwardRef(({ tooltipTitle = '', ...rest }, ref) => {
    const counterBody = jsx(CounterBody, { "data-testid": "Counter", ...rest, ref: ref });
    return (jsxs(Fragment, { children: [tooltipTitle && jsx(Tooltip, { title: tooltipTitle, children: counterBody }), !tooltipTitle && counterBody] }));
});

export { Counter };
